package main

type User struct {
    ID   int
    Name string
    Age  int
}

func FilterAdults(users []User) []User {
    var result []User
    for _, u := range users {
        if u.Age >= 18 {
            result = append(result, u)
        }
    }
    return result
}

func main() {
    users := []User{
        {ID: 1, Name: "Alice", Age: 25},
        {ID: 2, Name: "Bob", Age: 16},
    }
    adults := FilterAdults(users)
    fmt.Println(adults)
}

